parallax-layers.js:
const hero = document.getElementById('hero');
const bg = hero.querySelector('.parallax-bg');
const mid = hero.querySelector('.parallax-mid');
window.addEventListener('scroll', () => {
  const y = window.scrollY;
  bg.style.transform = `translateY(${y * 0.3}px)`;
  mid.style.transform = `translateY(${y * 0.6}px)`;
}, { passive: true });

sticky-reveal.js:
const phases = document.querySelectorAll('.reveal-phase');
const hero = document.getElementById('hero-wrapper');
window.addEventListener('scroll', () => {
  const progress = window.scrollY / (hero.offsetHeight - window.innerHeight);
  phases.forEach((el, i) => {
    el.classList.toggle('active', progress > i * 0.33);
  });
}, { passive: true });
